420	function createLazyArrayView<T>(load: () => T[]): T[] {
421	  return new Proxy([] as T[], {
422	    get(_target, prop) {
423	      const actual = load();
424	      const value = Reflect.get(actual, prop, actual);
425	      return typeof value === "function" ? value.bind(actual) : value;
426	    },
427	    has(_target, prop) {
428	      return Reflect.has(load(), prop);
429	    },
430	    ownKeys() {
431	      return Reflect.ownKeys(load());
432	    },
433	    getOwnPropertyDescriptor(_target, prop) {
434	      const actual = load();
435	      const descriptor = Reflect.getOwnPropertyDescriptor(actual, prop);
436	      if (descriptor) {
437	        return descriptor;
438	      }
439	      if (Reflect.has(actual, prop)) {
440	        return {
441	          configurable: true,
442	          enumerable: true,
443	          writable: false,
444	          value: Reflect.get(actual, prop, actual),
445	        };
446	      }
447	      return undefined;
448	    },
449	  });
450	}
