  "name": "@openclaw/pulseboard",
  "version": "2026.4.1-beta.1",
  "description": "OpenClaw PulseBoard channel plugin",
  "type": "module",
  "dependencies": {
    "pulseboard-sdk": "^1.0.0"  // Your protocol library
  },
  "devDependencies": {
    "openclaw": "workspace:*"
  },
  "peerDependencies": {
    "openclaw": ">=2026.4.1-beta.1"
  },
  "peerDependenciesMeta": {
    "openclaw": { "optional": true }
  },
  "openclaw": {
    "extensions": ["./index.ts"],
    "setupEntry": "./setup-entry.ts",
    "channel": {
      "id": "pulseboard",
      "label": "PulseBoard",
      "selectionLabel": "PulseBoard (Pulse Identity)",
      "detailLabel": "PulseBoard Channel",
      "docsPath": "/channels/pulseboard",
      "docsLabel": "pulseboard",
      "blurb": "Real-time pulse-based messaging with identity verification.",
      "systemImage": "waveform",
      "markdownCapable": true
    },
    "install": {
      "minHostVersion": ">=2026.4.1"
    }
  }
}
```

## INDEX.TS ENTRY POINT

