  channels: z.array(z.string()).optional(),
  markdown: z.object({
    tables: z.boolean().optional(),
  }).optional(),
}).strict();

// Top-level config with accounts support
export const PulseboardConfigSchema = PulseboardAccountSchema.extend({
  accounts: z.record(z.string(), PulseboardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((value, ctx) => {
  // Custom validations
});

// Export with UI support
export const PulseboardChannelConfigSchema = buildChannelConfigSchema(
  PulseboardConfigSchema,
  { uiHints: pulseboardConfigUiHints }
);
```

## TYPES.TS STRUCTURE

```typescript
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import type { OpenClawConfig } from "../api.js";

export interface PulseboardAccountConfig {
  enabled?: boolean;
  name?: string;
  pulseId?: string;
  apiKey?: SecretInput;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  channels?: string[];
}

export interface ResolvedPulseboardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  pulseId: string;
  apiKey: string;
  config: PulseboardAccountConfig;
}

export function listPulseboardAccountIds(cfg: OpenClawConfig): string[] {
  const pulseCfg = cfg.channels?.pulseboard as PulseboardAccountConfig | undefined;
  return pulseCfg?.apiKey ? [DEFAULT_ACCOUNT_ID] : [];
}

export function resolveDefaultPulseboardAccountId(cfg: OpenClawConfig): string {
  return DEFAULT_ACCOUNT_ID;
}

export function resolvePulseboardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseboardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? DEFAULT_ACCOUNT_ID);
  const pulseCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseboardAccountConfig
    | undefined;

  const apiKey = normalizeSecretInputString(pulseCfg?.apiKey) ?? "";
  const configured = Boolean(apiKey);

  return {
    accountId,
    name: pulseCfg?.name?.trim() || undefined,
    enabled: pulseCfg?.enabled !== false,
    configured,
    pulseId: pulseCfg?.pulseId ?? "",
    apiKey,
    config: { /* ... */ }
  };
}
```

## RUNTIME.TS PATTERN

```typescript
import type { PluginRuntime } from "openclaw/plugin-sdk/core";

let pulseboardRuntime: PluginRuntime | undefined;

export function setPulseboardRuntime(runtime: PluginRuntime) {
  pulseboardRuntime = runtime;
}

export function getPulseboardRuntime(): PluginRuntime {
  if (!pulseboardRuntime) {
    throw new Error("PulseBoard runtime not initialized");
  }
  return pulseboardRuntime;
}
```

## MAIN CHANNEL PLUGIN IMPLEMENTATION (src/channel.ts)

Uses the `createChatChannelPlugin()` helper from SDK:

```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { getChatChannelMeta, DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/...";

const meta = getChatChannelMeta("pulseboard");

export const pulseboardPlugin = createChatChannelPlugin<ResolvedPulseboardAccount>({
  id: "pulseboard",
  meta,

