    collectStatus: async (account) => {
      // Probe connectivity, check auth, etc.
    }
  }),

  // Groups (if supported)
  groups: { /* ... */ },

  // Directory/roster
  directory: createChannelDirectoryAdapter({
    listPeers: async (account) => [...],
    listGroups: async (account) => [...],
  })
});
```

