2. **src/config-schema.ts** - Zod schemas for configuration validation
3. **src/types.ts** - TypeScript interfaces for config, resolved accounts, probes
4. **src/runtime.ts** - Simple singleton getter/setter for the PluginRuntime
5. **src/setup-surface.ts** - Interactive setup wizard implementation

**Common Supporting Files:**

6. **src/accounts.ts** - Account resolution:
   - `listPulseboardAccountIds(cfg)`
   - `resolveDefaultPulseboardAccountId(cfg)`
   - `resolvePulseboardAccount({ cfg, accountId })`

7. **src/inbound.ts** - Inbound message handling and routing
8. **src/normalize.ts** - Normalize user/group targets, peer IDs
9. **src/send.ts** or outbound.ts - Send messages via protocol
10. **src/probe.ts** - Channel connectivity testing
11. **src/monitor.ts** - Health monitoring and status collection
12. **src/policy.ts** - Group access control and tool policies

**UI/Config:**
13. **src/config-ui-hints.ts** - UI hints for config fields

## CONFIG SCHEMA PATTERN

```typescript
import { buildChannelConfigSchema, DmPolicySchema } from "openclaw/plugin-sdk/channel-config-schema";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

// Per-account configuration schema
export const PulseboardAccountSchema = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  pulseId: z.string().optional(),
  apiKey: buildSecretInputSchema().optional(),
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  channels: z.array(z.string()).optional(),
  markdown: z.object({
    tables: z.boolean().optional(),
  }).optional(),
}).strict();

// Top-level config with accounts support
export const PulseboardConfigSchema = PulseboardAccountSchema.extend({
  accounts: z.record(z.string(), PulseboardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((value, ctx) => {
  // Custom validations
});

// Export with UI support
export const PulseboardChannelConfigSchema = buildChannelConfigSchema(
  PulseboardConfigSchema,
  { uiHints: pulseboardConfigUiHints }
);
```

## TYPES.TS STRUCTURE

```typescript
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import type { OpenClawConfig } from "../api.js";

export interface PulseboardAccountConfig {
  enabled?: boolean;
  name?: string;
  pulseId?: string;
  apiKey?: SecretInput;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  channels?: string[];
}

export interface ResolvedPulseboardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  pulseId: string;
  apiKey: string;
  config: PulseboardAccountConfig;
}

export function listPulseboardAccountIds(cfg: OpenClawConfig): string[] {
  const pulseCfg = cfg.channels?.pulseboard as PulseboardAccountConfig | undefined;
  return pulseCfg?.apiKey ? [DEFAULT_ACCOUNT_ID] : [];
}

export function resolveDefaultPulseboardAccountId(cfg: OpenClawConfig): string {
  return DEFAULT_ACCOUNT_ID;
}

export function resolvePulseboardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseboardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? DEFAULT_ACCOUNT_ID);
  const pulseCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseboardAccountConfig
    | undefined;

  const apiKey = normalizeSecretInputString(pulseCfg?.apiKey) ?? "";
  const configured = Boolean(apiKey);

  return {
    accountId,
    name: pulseCfg?.name?.trim() || undefined,
    enabled: pulseCfg?.enabled !== false,
    configured,
    pulseId: pulseCfg?.pulseId ?? "",
    apiKey,
    config: { /* ... */ }
  };
}
```

