125	export function sanitizeIrcTarget(raw: string): string {
126	  const decoded = decodeLiteralEscapes(raw);
127	  if (!decoded) {
128	    throw new Error("IRC target is required");
129	  }
130	  // Reject any surrounding whitespace instead of trimming it away.
131	  if (decoded !== decoded.trim()) {
132	    throw new Error(`Invalid IRC target: ${raw}`);
133	  }
134	  if (hasIrcControlChars(decoded)) {
135	    throw new Error(`Invalid IRC target: ${raw}`);
136	  }
137	  if (!IRC_TARGET_PATTERN.test(decoded)) {
138	    throw new Error(`Invalid IRC target: ${raw}`);
139	  }
140	  return decoded;
