66	function withTimeout<T>(promise: Promise<T>, timeoutMs: number, label: string): Promise<T> {
67	  return new Promise((resolve, reject) => {
68	    const timer = setTimeout(
69	      () => reject(new Error(`${label} timed out after ${timeoutMs}ms`)),
70	      timeoutMs,
71	    );
72	    promise
73	      .then((result) => {
74	        clearTimeout(timer);
75	        resolve(result);
76	      })
77	      .catch((error) => {
78	        clearTimeout(timer);
79	        reject(error);
80	      });
81	  });
82	}
