84	function buildFallbackNick(nick: string): string {
85	  const normalized = nick.replace(/\s+/g, "");
86	  const safe = normalized.replace(/[^A-Za-z0-9_\-\[\]\\`^{}|]/g, "");
87	  const base = safe || "openclaw";
88	  const suffix = "_";
89	  const maxNickLen = 30;
90	  if (base.length >= maxNickLen) {
91	    return `${base.slice(0, maxNickLen - suffix.length)}${suffix}`;
92	  }
93	  return `${base}${suffix}`;
94	}
