96	export function buildIrcNickServCommands(options?: IrcNickServOptions): string[] {
97	  if (!options || options.enabled === false) {
98	    return [];
99	  }
100	  const password = sanitizeIrcOutboundText(options.password ?? "");
101	  if (!password) {
102	    return [];
103	  }
104	  const service = sanitizeIrcTarget(options.service?.trim() || "NickServ");
105	  const commands = [`PRIVMSG ${service} :IDENTIFY ${password}`];
106	  if (options.register) {
107	    const registerEmail = sanitizeIrcOutboundText(options.registerEmail ?? "");
108	    if (!registerEmail) {
109	      throw new Error("IRC NickServ register requires registerEmail");
110	    }
111	    commands.push(`PRIVMSG ${service} :REGISTER ${password} ${registerEmail}`);
112	  }
113	  return commands;
114	}
