267	      buffer = buffer.slice(idx + 1);
268	      idx = buffer.indexOf("\n");
269	
270	      if (!rawLine) {
271	        continue;
272	      }
273	      if (options.onLine) {
274	        options.onLine(rawLine);
275	      }
276	
277	      const line = parseIrcLine(rawLine);
