311	        return;
312	      }
313	
314	      if (!ready && IRC_ERROR_CODES.has(line.command)) {
315	        const detail =
316	          line.trailing != null ? line.trailing : line.params.join(" ") || "login rejected";
317	        fail(new Error(`IRC login failed (${line.command}): ${detail}`));
318	        close();
319	        return;
320	      }
321	
322	      if (line.command === "001") {
323	        ready = true;
324	        const nickParam = line.params[0];
325	        if (nickParam && nickParam.trim()) {
326	          currentNick = nickParam.trim();
327	        }
328	        try {
329	          const nickServCommands = buildIrcNickServCommands(options.nickserv);
330	          for (const command of nickServCommands) {
331	            sendRaw(command);
332	          }
333	        } catch (err) {
334	          fail(err);
335	        }
336	        for (const channel of options.channels || []) {
337	          const trimmed = channel.trim();
338	          if (!trimmed) {
339	            continue;
340	          }
341	          try {
342	            join(trimmed);
343	          } catch (err) {
344	            fail(err);
345	          }
346	        }
347	        if (resolveReady) {
348	          resolveReady();
349	        }
350	        resolveReady = null;
351	        rejectReady = null;
352	        continue;
353	      }
354	
355	      if (line.command === "NOTICE") {
356	        if (options.onNotice) {
357	          options.onNotice(line.trailing != null ? line.trailing : "", line.params[0]);
358	        }
359	        continue;
360	      }
361	
362	      if (line.command === "PRIVMSG") {
363	        const targetParam = line.params[0];
364	        const target = targetParam ? targetParam.trim() : "";
365	        const text = line.trailing != null ? line.trailing : "";
366	        const prefix = parseIrcPrefix(line.prefix);
367	        const senderNick = prefix.nick ? prefix.nick.trim() : "";
368	        if (!target || !senderNick || !text.trim()) {
369	          continue;
370	        }
371	        if (options.onPrivmsg) {
372	          void Promise.resolve(
373	            options.onPrivmsg({
374	              senderNick,
375	              senderUser: prefix.user ? prefix.user.trim() : undefined,
376	              senderHost: prefix.host ? prefix.host.trim() : undefined,
377	              target,
378	              text,
379	              rawLine,
380	            }),
381	          ).catch((error) => {
382	            fail(error);
383	          });
384	        }
385	      }
386	    }
387	  });
388	
389	  socket.once("connect", () => {
390	    try {
391	      if (options.password && options.password.trim()) {
392	        sendRaw(`PASS ${options.password.trim()}`);
393	      }
394	      sendRaw(`NICK ${options.nick.trim()}`);
395	      sendRaw(`USER ${options.username.trim()} 0 * :${sanitizeIrcOutboundText(options.realname)}`);
396	    } catch (err) {
397	      fail(err);
398	      close();
