400	  });
401	
402	  socket.once("error", (err: unknown) => {
403	    fail(err);
404	  });
405	
406	  socket.once("close", () => {
407	    if (!closed) {
408	      closed = true;
409	      if (!ready) {
410	        fail(new Error("IRC connection closed before ready"));
