147	  /** Stop the bus and close connections */
148	  close: () => void;
149	  /** Get the bot's public key */
150	  publicKey: string;
151	  /** Send a DM to a pubkey */
152	  sendDm: (toPubkey: string, text: string) => Promise<void>;
153	  /** Get current metrics snapshot */
154	  getMetrics: () => MetricsSnapshot;
155	  /** Publish a profile (kind:0) to all relays */
156	  publishProfile: (profile: NostrProfile) => Promise<ProfilePublishResult>;
157	  /** Get the last profile publish state */
158	  getProfileState: () => Promise<{
159	    lastPublishedAt: number | null;
160	    lastPublishedEventId: string | null;
161	    lastPublishResults: Record<string, "ok" | "failed" | "timeout"> | null;
162	  }>;
163	}
