165	// ============================================================================
166	// Circuit Breaker
167	// ============================================================================
168	
169	interface CircuitBreakerState {
170	  state: "closed" | "open" | "half_open";
171	  failures: number;
172	  lastFailure: number;
173	  lastSuccess: number;
174	}
175	
176	interface CircuitBreaker {
177	  /** Check if requests should be allowed */
178	  canAttempt: () => boolean;
179	  /** Record a success */
180	  recordSuccess: () => void;
181	  /** Record a failure */
182	  recordFailure: () => void;
183	  /** Get current state */
184	  getState: () => CircuitBreakerState["state"];
185	}
186	
187	function createCircuitBreaker(
188	  relay: string,
189	  metrics: NostrMetrics,
190	  threshold: number = CIRCUIT_BREAKER_THRESHOLD,
191	  resetMs: number = CIRCUIT_BREAKER_RESET_MS,
192	): CircuitBreaker {
193	  const state: CircuitBreakerState = {
194	    state: "closed",
195	    failures: 0,
196	    lastFailure: 0,
197	    lastSuccess: Date.now(),
198	  };
199	
200	  return {
201	    canAttempt(): boolean {
202	      if (state.state === "closed") {
203	        return true;
204	      }
205	
206	      if (state.state === "open") {
207	        // Check if enough time has passed to try half-open
208	        if (Date.now() - state.lastFailure >= resetMs) {
209	          state.state = "half_open";
210	          metrics.emit("relay.circuit_breaker.half_open", 1, { relay });
211	          return true;
212	        }
213	        return false;
214	      }
215	
216	      // half_open: allow one attempt
217	      return true;
218	    },
219	
220	    recordSuccess(): void {
221	      if (state.state === "half_open") {
222	        state.state = "closed";
223	        state.failures = 0;
224	        metrics.emit("relay.circuit_breaker.close", 1, { relay });
225	      } else if (state.state === "closed") {
226	        state.failures = 0;
227	      }
228	      state.lastSuccess = Date.now();
229	    },
230	
231	    recordFailure(): void {
232	      state.failures++;
233	      state.lastFailure = Date.now();
234	
235	      if (state.state === "half_open") {
236	        state.state = "open";
237	        metrics.emit("relay.circuit_breaker.open", 1, { relay });
238	      } else if (state.state === "closed" && state.failures >= threshold) {
239	        state.state = "open";
240	        metrics.emit("relay.circuit_breaker.open", 1, { relay });
241	      }
242	    },
243	
244	    getState(): CircuitBreakerState["state"] {
245	      return state.state;
246	    },
247	  };
248	}
