382	// ============================================================================
383	// Main Bus
384	// ============================================================================
385	
386	/**
387	 * Start the Nostr DM bus - subscribes to NIP-04 encrypted DMs
388	 */
389	export async function startNostrBus(options: NostrBusOptions): Promise<NostrBusHandle> {
390	  const {
391	    privateKey,
392	    relays = DEFAULT_RELAYS,
393	    onMessage,
394	    authorizeSender,
395	    onError,
396	    onEose,
397	    onMetric,
398	    maxSeenEntries = 100_000,
399	    seenTtlMs = 60 * 60 * 1000,
400	  } = options;
401	
402	  const sk = validatePrivateKey(privateKey);
403	  const pk = getPublicKey(sk);
404	  const pool = new SimplePool();
405	  const accountId = options.accountId ?? pk.slice(0, 16);
406	  const gatewayStartedAt = Math.floor(Date.now() / 1000);
407	  const guardPolicy = createDirectDmPreCryptoGuardPolicy({
408	    ...DEFAULT_INBOUND_GUARD_POLICY,
409	    ...options.guardPolicy,
410	    rateLimit: {
411	      ...DEFAULT_INBOUND_GUARD_POLICY.rateLimit,
412	      ...options.guardPolicy?.rateLimit,
413	    },
414	  });
415	
416	  // Initialize metrics
417	  const metrics = onMetric ? createMetrics(onMetric) : createNoopMetrics();
418	
419	  // Initialize seen tracker with LRU
420	  const seen: SeenTracker = createSeenTracker({
421	    maxEntries: maxSeenEntries,
422	    ttlMs: seenTtlMs,
423	  });
424	
425	  // Initialize circuit breakers and health tracker
426	  const circuitBreakers = new Map<string, CircuitBreaker>();
427	  const healthTracker = createRelayHealthTracker();
428	
429	  for (const relay of relays) {
430	    circuitBreakers.set(relay, createCircuitBreaker(relay, metrics));
431	  }
432	
433	  // Read persisted state and compute `since` timestamp (with small overlap)
434	  const state = await readNostrBusState({ accountId });
435	  const baseSince = computeSinceTimestamp(state, gatewayStartedAt);
436	  const since = Math.max(0, baseSince - STARTUP_LOOKBACK_SEC);
437	
438	  // Seed in-memory dedupe with recent IDs from disk (prevents restart replay)
439	  if (state?.recentEventIds?.length) {
440	    seen.seed(state.recentEventIds);
441	  }
442	
443	  // Persist startup timestamp
444	  await writeNostrBusState({
445	    accountId,
446	    lastProcessedAt: state?.lastProcessedAt ?? gatewayStartedAt,
447	    gatewayStartedAt,
448	    recentEventIds: state?.recentEventIds ?? [],
449	  });
450	
451	  // Debounced state persistence
452	  let pendingWrite: ReturnType<typeof setTimeout> | undefined;
453	  let lastProcessedAt = state?.lastProcessedAt ?? gatewayStartedAt;
454	  let recentEventIds = (state?.recentEventIds ?? []).slice(-MAX_PERSISTED_EVENT_IDS);
455	
456	  function scheduleStatePersist(eventCreatedAt: number, eventId: string): void {
457	    lastProcessedAt = Math.max(lastProcessedAt, eventCreatedAt);
458	    recentEventIds.push(eventId);
459	    if (recentEventIds.length > MAX_PERSISTED_EVENT_IDS) {
460	      recentEventIds = recentEventIds.slice(-MAX_PERSISTED_EVENT_IDS);
461	    }
462	
463	    if (pendingWrite) {
464	      clearTimeout(pendingWrite);
465	    }
466	    pendingWrite = setTimeout(() => {
467	      writeNostrBusState({
468	        accountId,
469	        lastProcessedAt,
470	        gatewayStartedAt,
471	        recentEventIds,
472	      }).catch((err) => onError?.(err as Error, "persist state"));
473	    }, STATE_PERSIST_DEBOUNCE_MS);
474	  }
475	
476	  const inflight = new Set<string>();
477	  const perSenderRateLimiter = createFixedWindowRateLimiter({
478	    windowMs: guardPolicy.rateLimit.windowMs,
479	    maxRequests: guardPolicy.rateLimit.maxPerSenderPerWindow,
480	    maxTrackedKeys: guardPolicy.rateLimit.maxTrackedSenderKeys,
481	  });
482	  const globalRateLimiter = createFixedWindowRateLimiter({
483	    windowMs: guardPolicy.rateLimit.windowMs,
484	    maxRequests: guardPolicy.rateLimit.maxGlobalPerWindow,
485	    maxTrackedKeys: 1,
486	  });
487	
488	  const updateRateLimiterSizeMetric = () => {
489	    metrics.emit(
490	      "memory.rate_limiter_entries",
491	      perSenderRateLimiter.size() + globalRateLimiter.size(),
492	    );
493	  };
494	
495	  // Event handler
496	  async function handleEvent(event: Event): Promise<void> {
497	    try {
498	      metrics.emit("event.received");
499	
500	      // Fast dedupe check (handles relay reconnections)
501	      if (seen.peek(event.id) || inflight.has(event.id)) {
502	        metrics.emit("event.duplicate");
503	        return;
504	      }
505	      inflight.add(event.id);
506	
507	      // Self-message loop prevention: skip our own messages
508	      if (event.pubkey === pk) {
509	        metrics.emit("event.rejected.self_message");
510	        return;
511	      }
512	
513	      // Skip events older than our `since` (relay may ignore filter)
514	      if (event.created_at < since) {
515	        metrics.emit("event.rejected.stale");
516	        return;
517	      }
518	
519	      if (event.created_at > Math.floor(Date.now() / 1000) + guardPolicy.maxFutureSkewSec) {
520	        metrics.emit("event.rejected.future");
521	        return;
522	      }
523	
524	      if (!guardPolicy.allowedKinds.includes(event.kind)) {
525	        metrics.emit("event.rejected.wrong_kind");
526	        return;
527	      }
528	
529	      // Fast p-tag check BEFORE crypto (no allocation, cheaper)
530	      let targetsUs = false;
531	      for (const t of event.tags) {
532	        if (t[0] === "p" && t[1] === pk) {
533	          targetsUs = true;
534	          break;
535	        }
536	      }
537	      if (!targetsUs) {
538	        metrics.emit("event.rejected.wrong_kind");
539	        return;
540	      }
541	
542	      const replyTo = async (text: string): Promise<void> => {
543	        await sendEncryptedDm(
544	          pool,
545	          sk,
546	          event.pubkey,
547	          text,
548	          relays,
549	          metrics,
550	          circuitBreakers,
551	          healthTracker,
552	          onError,
553	        );
554	      };
555	
556	      const rejectIfGlobalRateLimited = (): boolean => {
557	        updateRateLimiterSizeMetric();
558	        if (globalRateLimiter.isRateLimited("global")) {
559	          metrics.emit("rate_limit.global");
560	          metrics.emit("event.rejected.rate_limited");
561	          updateRateLimiterSizeMetric();
562	          return true;
563	        }
564	        updateRateLimiterSizeMetric();
565	        return false;
566	      };
567	
568	      const rejectIfVerifiedSenderRateLimited = (): boolean => {
569	        updateRateLimiterSizeMetric();
570	        if (perSenderRateLimiter.isRateLimited(event.pubkey)) {
571	          metrics.emit("rate_limit.per_sender");
572	          metrics.emit("event.rejected.rate_limited");
573	          updateRateLimiterSizeMetric();
574	          return true;
575	        }
576	        updateRateLimiterSizeMetric();
577	        return false;
578	      };
579	
580	      const markSeen = () => {
581	        seen.add(event.id);
582	        metrics.emit("memory.seen_tracker_size", seen.size());
583	      };
584	
585	      if (Buffer.byteLength(event.content, "utf8") > guardPolicy.maxCiphertextBytes) {
586	        if (rejectIfGlobalRateLimited()) {
587	          return;
588	        }
589	        metrics.emit("event.rejected.oversized_ciphertext");
590	        return;
591	      }
592	
593	      if (rejectIfGlobalRateLimited()) {
594	        return;
595	      }
596	
597	      // Verify signature (must pass before we trust the event)
598	      if (!verifyEvent(event)) {
599	        metrics.emit("event.rejected.invalid_signature");
600	        onError?.(new Error("Invalid signature"), `event ${event.id}`);
601	        return;
602	      }
603	
604	      if (rejectIfVerifiedSenderRateLimited()) {
605	        return;
606	      }
607	
608	      if (authorizeSender) {
609	        const decision = await authorizeSender({
610	          senderPubkey: event.pubkey,
611	          reply: replyTo,
612	        });
613	        if (decision !== "allow") {
614	          markSeen();
615	          return;
616	        }
617	      }
618	
619	      // Mark seen AFTER verify (don't cache invalid IDs)
620	      markSeen();
621	
622	      // Decrypt the message
623	      let plaintext: string;
624	      try {
625	        plaintext = decrypt(sk, event.pubkey, event.content);
626	        metrics.emit("decrypt.success");
627	      } catch (err) {
628	        metrics.emit("decrypt.failure");
629	        metrics.emit("event.rejected.decrypt_failed");
630	        onError?.(err as Error, `decrypt from ${event.pubkey}`);
631	        return;
632	      }
633	
634	      if (Buffer.byteLength(plaintext, "utf8") > guardPolicy.maxPlaintextBytes) {
635	        metrics.emit("event.rejected.oversized_plaintext");
636	        return;
637	      }
638	
639	      // Call the message handler
640	      await onMessage(event.pubkey, plaintext, replyTo, {
641	        eventId: event.id,
642	        createdAt: event.created_at,
643	      });
644	
645	      // Mark as processed
646	      metrics.emit("event.processed");
647	
648	      // Persist progress (debounced)
649	      scheduleStatePersist(event.created_at, event.id);
650	    } catch (err) {
651	      onError?.(err as Error, `event ${event.id}`);
652	    } finally {
653	      inflight.delete(event.id);
654	    }
655	  }
656	
657	  const sub = pool.subscribeMany(
658	    relays,
659	    [{ kinds: [4], "#p": [pk], since }] as unknown as Parameters<typeof pool.subscribeMany>[1],
660	    {
661	      onevent: handleEvent,
662	      oneose: () => {
663	        // EOSE handler - called when all stored events have been received
664	        for (const relay of relays) {
665	          metrics.emit("relay.message.eose", 1, { relay });
666	        }
667	        onEose?.(relays.join(", "));
668	      },
669	      onclose: (reason) => {
670	        // Handle subscription close
671	        for (const relay of relays) {
672	          metrics.emit("relay.message.closed", 1, { relay });
673	          options.onDisconnect?.(relay);
674	        }
675	        onError?.(new Error(`Subscription closed: ${reason.join(", ")}`), "subscription");
676	      },
677	    },
678	  );
679	
680	  // Public sendDm function
681	  const sendDm = async (toPubkey: string, text: string): Promise<void> => {
682	    await sendEncryptedDm(
683	      pool,
684	      sk,
685	      toPubkey,
686	      text,
687	      relays,
688	      metrics,
689	      circuitBreakers,
690	      healthTracker,
691	      onError,
692	    );
693	  };
694	
695	  // Profile publishing function
696	  const publishProfile = async (profile: NostrProfile): Promise<ProfilePublishResult> => {
697	    // Read last published timestamp for monotonic ordering
698	    const profileState = await readNostrProfileState({ accountId });
699	    const lastPublishedAt = profileState?.lastPublishedAt ?? undefined;
700	
701	    // Publish the profile
702	    const result = await publishProfileFn(pool, sk, relays, profile, lastPublishedAt);
703	
704	    // Convert results to state format
705	    const publishResults: Record<string, "ok" | "failed" | "timeout"> = {};
706	    for (const relay of result.successes) {
707	      publishResults[relay] = "ok";
708	    }
709	    for (const { relay, error } of result.failures) {
710	      publishResults[relay] = error === "timeout" ? "timeout" : "failed";
711	    }
712	
713	    // Persist the publish state
714	    await writeNostrProfileState({
715	      accountId,
716	      lastPublishedAt: result.createdAt,
717	      lastPublishedEventId: result.eventId,
718	      lastPublishResults: publishResults,
719	    });
720	
721	    return result;
722	  };
723	
724	  // Get profile state function
725	  const getProfileState = async () => {
726	    const state = await readNostrProfileState({ accountId });
727	    return {
728	      lastPublishedAt: state?.lastPublishedAt ?? null,
729	      lastPublishedEventId: state?.lastPublishedEventId ?? null,
730	      lastPublishResults: state?.lastPublishResults ?? null,
731	    };
732	  };
733	
734	  return {
735	    close: () => {
736	      sub.close();
737	      seen.stop();
738	      perSenderRateLimiter.clear();
739	      globalRateLimiter.clear();
740	      // Flush pending state write synchronously on close
741	      if (pendingWrite) {
742	        clearTimeout(pendingWrite);
743	        writeNostrBusState({
744	          accountId,
745	          lastProcessedAt,
746	          gatewayStartedAt,
747	          recentEventIds,
748	        }).catch((err) => onError?.(err as Error, "persist state on close"));
749	      }
750	    },
751	    publicKey: pk,
752	    sendDm,
753	    getMetrics: () => metrics.getSnapshot(),
754	    publishProfile,
755	    getProfileState,
756	  };
757	}
