759	// ============================================================================
760	// Send DM with Circuit Breaker + Health Scoring
761	// ============================================================================
762	
763	/**
764	 * Send an encrypted DM to a pubkey
765	 */
766	async function sendEncryptedDm(
767	  pool: SimplePool,
768	  sk: Uint8Array,
769	  toPubkey: string,
770	  text: string,
771	  relays: string[],
772	  metrics: NostrMetrics,
773	  circuitBreakers: Map<string, CircuitBreaker>,
774	  healthTracker: RelayHealthTracker,
775	  onError?: (error: Error, context: string) => void,
776	): Promise<void> {
777	  const ciphertext = encrypt(sk, toPubkey, text);
778	  const reply = finalizeEvent(
779	    {
780	      kind: 4,
781	      content: ciphertext,
782	      tags: [["p", toPubkey]],
783	      created_at: Math.floor(Date.now() / 1000),
784	    },
785	    sk,
786	  );
787	
788	  // Sort relays by health score (best first)
789	  const sortedRelays = healthTracker.getSortedRelays(relays);
790	
791	  // Try relays in order of health, respecting circuit breakers
792	  let lastError: Error | undefined;
793	  for (const relay of sortedRelays) {
794	    const cb = circuitBreakers.get(relay);
795	
796	    // Skip if circuit breaker is open
797	    if (cb && !cb.canAttempt()) {
798	      continue;
799	    }
800	
801	    const startTime = Date.now();
802	    try {
803	      // oxlint-disable-next-line typescript/await-thenable typesciript/no-floating-promises
804	      await pool.publish([relay], reply);
805	      const latency = Date.now() - startTime;
806	
807	      // Record success
808	      cb?.recordSuccess();
809	      healthTracker.recordSuccess(relay, latency);
810	
811	      return; // Success - exit early
812	    } catch (err) {
813	      lastError = err as Error;
814	      const latency = Date.now() - startTime;
815	
816	      // Record failure
817	      cb?.recordFailure();
818	      healthTracker.recordFailure(relay);
819	      metrics.emit("relay.error", 1, { relay, latency });
820	
821	      onError?.(lastError, `publish to ${relay}`);
822	    }
823	  }
824	
825	  throw new Error(`Failed to publish to any relay: ${lastError?.message}`);
826	}
827	
828	// ============================================================================
829	// Pubkey Utilities
830	// ============================================================================
831	
832	/**
833	 * Check if a string looks like a valid Nostr pubkey (hex or npub)
834	 */
835	export function isValidPubkey(input: string): boolean {
836	  if (typeof input !== "string") {
837	    return false;
838	  }
839	  const trimmed = input.trim();
840	
841	  // npub format
842	  if (trimmed.startsWith("npub1")) {
843	    try {
844	      const decoded = nip19.decode(trimmed);
845	      return decoded.type === "npub";
846	    } catch {
847	      return false;
848	    }
849	  }
850	
851	  // Hex format
852	  return /^[0-9a-fA-F]{64}$/.test(trimmed);
853	}
854	
855	/**
856	 * Normalize a pubkey to hex format (accepts npub or hex)
857	 */
858	export function normalizePubkey(input: string): string {
859	  const trimmed = input.trim();
860	
861	  // npub format - decode to hex
862	  if (trimmed.startsWith("npub1")) {
863	    const decoded = nip19.decode(trimmed);
864	    if (decoded.type !== "npub") {
865	      throw new Error("Invalid npub key");
866	    }
867	    // Convert Uint8Array to hex string
868	    return Array.from(decoded.data as unknown as Uint8Array)
869	      .map((b) => b.toString(16).padStart(2, "0"))
870	      .join("");
871	  }
872	
873	  // Already hex - validate and return lowercase
874	  if (!/^[0-9a-fA-F]{64}$/.test(trimmed)) {
875	    throw new Error("Pubkey must be 64 hex characters or npub format");
876	  }
877	  return trimmed.toLowerCase();
878	}
879	
880	/**
881	 * Convert a hex pubkey to npub format
882	 */
883	export function pubkeyToNpub(hexPubkey: string): string {
884	  const normalized = normalizePubkey(hexPubkey);
885	  // npubEncode expects a hex string, not Uint8Array
886	  return nip19.npubEncode(normalized);
887	}
