153	// Profile Publishing
154	// ============================================================================
155	
156	/** Per-relay publish timeout (ms) */
157	const RELAY_PUBLISH_TIMEOUT_MS = 5000;
158	
159	/**
160	 * Publish a profile event to multiple relays.
161	 *
162	 * Best-effort: publishes to all relays in parallel, reports per-relay results.
163	 * Does NOT retry automatically - caller should handle retries if needed.
164	 *
165	 * @param pool - SimplePool instance for relay connections
166	 * @param relays - Array of relay WebSocket URLs
167	 * @param event - Signed profile event (kind:0)
168	 * @returns Publish results with successes and failures
169	 */
170	export async function publishProfileEvent(
171	  pool: SimplePool,
172	  relays: string[],
173	  event: Event,
174	): Promise<ProfilePublishResult> {
175	  const successes: string[] = [];
176	  const failures: Array<{ relay: string; error: string }> = [];
177	
178	  // Publish to each relay in parallel with timeout
179	  const publishPromises = relays.map(async (relay) => {
180	    try {
181	      const timeoutPromise = new Promise<never>((_, reject) => {
182	        setTimeout(() => reject(new Error("timeout")), RELAY_PUBLISH_TIMEOUT_MS);
183	      });
184	
185	      // oxlint-disable-next-line typescript/no-floating-promises
186	      await Promise.race([pool.publish([relay], event), timeoutPromise]);
187	
188	      successes.push(relay);
189	    } catch (err) {
190	      const errorMessage = err instanceof Error ? err.message : String(err);
191	      failures.push({ relay, error: errorMessage });
192	    }
193	  });
194	
195	  await Promise.all(publishPromises);
196	
197	  return {
198	    eventId: event.id,
199	    successes,
200	    failures,
201	    createdAt: event.created_at,
202	  };
203	}
