152	/**
153	 * Determine the `since` timestamp for subscription.
154	 * Returns the later of: lastProcessedAt or gatewayStartedAt (both from disk),
155	 * falling back to `now` for fresh starts.
156	 */
157	export function computeSinceTimestamp(
158	  state: NostrBusState | null,
159	  nowSec: number = Math.floor(Date.now() / 1000),
160	): number {
161	  if (!state) {
162	    return nowSec;
163	  }
164	
165	  // Use the most recent timestamp we have
166	  const candidates = [state.lastProcessedAt, state.gatewayStartedAt].filter(
167	    (t): t is number => t !== null && t > 0,
168	  );
169	
170	  if (candidates.length === 0) {
171	    return nowSec;
172	  }
173	  return Math.max(...candidates);
174	}
