374	async function handleGetProfile(
375	  accountId: string,
376	  ctx: NostrProfileHttpContext,
377	  res: ServerResponse,
378	): Promise<true> {
379	  const configProfile = ctx.getConfigProfile(accountId);
380	  const publishState = await getNostrProfileState(accountId);
381	
382	  sendJson(res, 200, {
383	    ok: true,
384	    profile: configProfile ?? null,
385	    publishState: publishState ?? null,
386	  });
