390	// ============================================================================
391	// PUT /api/channels/nostr/:accountId/profile
392	// ============================================================================
393	
394	async function handleUpdateProfile(
395	  accountId: string,
396	  ctx: NostrProfileHttpContext,
397	  req: IncomingMessage,
398	  res: ServerResponse,
399	): Promise<true> {
400	  if (!enforceLoopbackMutationGuards(ctx, req, res)) {
401	    return true;
402	  }
403	
404	  // Rate limiting
405	  if (!checkRateLimit(accountId)) {
406	    sendJson(res, 429, { ok: false, error: "Rate limit exceeded (5 requests/minute)" });
407	    return true;
408	  }
409	
410	  // Parse body
411	  let body: unknown;
412	  try {
413	    body = await readJsonBody(req);
414	  } catch (err) {
415	    sendJson(res, 400, { ok: false, error: String(err) });
416	    return true;
417	  }
418	
419	  // Validate profile
420	  const parseResult = ProfileUpdateSchema.safeParse(body);
421	  if (!parseResult.success) {
422	    const errors = parseResult.error.issues.map((i) => `${i.path.join(".")}: ${i.message}`);
423	    sendJson(res, 400, { ok: false, error: "Validation failed", details: errors });
424	    return true;
425	  }
426	
427	  const profile = parseResult.data;
428	
429	  // SSRF check for picture URL
430	  if (profile.picture) {
431	    const pictureCheck = validateUrlSafety(profile.picture);
432	    if (!pictureCheck.ok) {
433	      sendJson(res, 400, { ok: false, error: `picture: ${pictureCheck.error}` });
434	      return true;
435	    }
436	  }
437	
438	  // SSRF check for banner URL
439	  if (profile.banner) {
440	    const bannerCheck = validateUrlSafety(profile.banner);
441	    if (!bannerCheck.ok) {
442	      sendJson(res, 400, { ok: false, error: `banner: ${bannerCheck.error}` });
443	      return true;
444	    }
445	  }
446	
447	  // SSRF check for website URL
448	  if (profile.website) {
449	    const websiteCheck = validateUrlSafety(profile.website);
450	    if (!websiteCheck.ok) {
451	      sendJson(res, 400, { ok: false, error: `website: ${websiteCheck.error}` });
452	      return true;
453	    }
454	  }
455	
456	  // Merge with existing profile to preserve unknown fields
457	  const existingProfile = ctx.getConfigProfile(accountId) ?? {};
458	  const mergedProfile: NostrProfile = {
459	    ...existingProfile,
460	    ...profile,
461	  };
462	
463	  // Publish with mutex to prevent concurrent publishes
464	  try {
465	    const result = await withPublishLock(accountId, async () => {
466	      return await publishNostrProfile(accountId, mergedProfile);
467	    });
468	
469	    // Only persist if at least one relay succeeded
470	    if (result.successes.length > 0) {
471	      await ctx.updateConfigProfile(accountId, mergedProfile);
472	      ctx.log?.info(`[${accountId}] Profile published to ${result.successes.length} relay(s)`);
473	    } else {
474	      ctx.log?.warn(`[${accountId}] Profile publish failed on all relays`);
475	    }
476	
477	    sendJson(res, 200, {
478	      ok: true,
479	      eventId: result.eventId,
480	      createdAt: result.createdAt,
481	      successes: result.successes,
482	      failures: result.failures,
483	      persisted: result.successes.length > 0,
484	    });
485	  } catch (err) {
486	    ctx.log?.error(`[${accountId}] Profile publish error: ${String(err)}`);
487	    sendJson(res, 500, { ok: false, error: `Publish failed: ${String(err)}` });
488	  }
489	
490	  return true;
491	}
