493	// ============================================================================
494	// POST /api/channels/nostr/:accountId/profile/import
495	// ============================================================================
496	
497	async function handleImportProfile(
498	  accountId: string,
499	  ctx: NostrProfileHttpContext,
500	  req: IncomingMessage,
501	  res: ServerResponse,
502	): Promise<true> {
503	  if (!enforceLoopbackMutationGuards(ctx, req, res)) {
504	    return true;
505	  }
506	
507	  // Get account info
508	  const accountInfo = ctx.getAccountInfo(accountId);
509	  if (!accountInfo) {
510	    sendJson(res, 404, { ok: false, error: `Account not found: ${accountId}` });
511	    return true;
512	  }
513	
514	  const { pubkey, relays } = accountInfo;
515	
516	  if (!pubkey) {
517	    sendJson(res, 400, { ok: false, error: "Account has no public key configured" });
518	    return true;
519	  }
520	
521	  // Parse options from body
522	  let autoMerge = false;
523	  try {
524	    const body = await readJsonBody(req);
525	    if (typeof body === "object" && body !== null) {
526	      autoMerge = (body as { autoMerge?: boolean }).autoMerge === true;
527	    }
528	  } catch {
529	    // Ignore body parse errors - use defaults
530	  }
531	
532	  ctx.log?.info(`[${accountId}] Importing profile for ${pubkey.slice(0, 8)}...`);
533	
534	  // Import from relays
535	  const result = await importProfileFromRelays({
536	    pubkey,
537	    relays,
538	    timeoutMs: 10_000, // 10 seconds for import
539	  });
540	
541	  if (!result.ok) {
542	    sendJson(res, 200, {
543	      ok: false,
544	      error: result.error,
545	      relaysQueried: result.relaysQueried,
546	    });
547	    return true;
548	  }
549	
550	  // If autoMerge is requested, merge and save
551	  if (autoMerge && result.profile) {
552	    const localProfile = ctx.getConfigProfile(accountId);
553	    const merged = mergeProfiles(localProfile, result.profile);
554	    await ctx.updateConfigProfile(accountId, merged);
555	    ctx.log?.info(`[${accountId}] Profile imported and merged`);
556	
557	    sendJson(res, 200, {
558	      ok: true,
559	      imported: result.profile,
560	      merged,
561	      saved: true,
562	      event: result.event,
563	      sourceRelay: result.sourceRelay,
564	      relaysQueried: result.relaysQueried,
565	    });
566	    return true;
567	  }
568	
569	  // Otherwise, just return the imported profile for review
570	  sendJson(res, 200, {
571	    ok: true,
572	    imported: result.profile,
573	    saved: false,
574	    event: result.event,
575	    sourceRelay: result.sourceRelay,
576	    relaysQueried: result.relaysQueried,
577	  });
578	  return true;
579	}
