36	export interface ProfileImportOptions {
37	  /** The public key to fetch profile for */
38	  pubkey: string;
39	  /** Relay URLs to query */
40	  relays: string[];
41	  /** Timeout per relay in milliseconds (default: 5000) */
42	  timeoutMs?: number;
