55	/**
56	 * Sanitize URLs in an imported profile to prevent SSRF attacks.
57	 * Removes any URLs that don't pass SSRF validation.
58	 */
59	function sanitizeProfileUrls(profile: NostrProfile): NostrProfile {
60	  const result = { ...profile };
61	  const urlFields = ["picture", "banner", "website"] as const;
62	
63	  for (const field of urlFields) {
64	    const value = result[field];
65	    if (value && typeof value === "string") {
66	      const validation = validateUrlSafety(value);
67	      if (!validation.ok) {
68	        // Remove unsafe URL
69	        delete result[field];
70	      }
71	    }
72	  }
73	
74	  return result;
75	}
