77	/**
78	 * Fetch the latest kind:0 profile event for a pubkey from relays.
79	 *
80	 * - Queries all relays in parallel
81	 * - Takes the event with the highest created_at
82	 * - Verifies the event signature
83	 * - Parses and returns the profile
84	 */
85	export async function importProfileFromRelays(
86	  opts: ProfileImportOptions,
87	): Promise<ProfileImportResult> {
88	  const { pubkey, relays, timeoutMs = DEFAULT_TIMEOUT_MS } = opts;
89	
90	  if (!pubkey || !/^[0-9a-fA-F]{64}$/.test(pubkey)) {
91	    return {
92	      ok: false,
93	      error: "Invalid pubkey format (must be 64 hex characters)",
94	      relaysQueried: [],
95	    };
96	  }
97	
98	  if (relays.length === 0) {
99	    return {
100	      ok: false,
101	      error: "No relays configured",
102	      relaysQueried: [],
103	    };
104	  }
105	
106	  const pool = new SimplePool();
107	  const relaysQueried: string[] = [];
108	
109	  try {
110	    // Query all relays for kind:0 events from this pubkey
111	    const events: Array<{ event: Event; relay: string }> = [];
112	
113	    // Create timeout promise
114	    const timeoutPromise = new Promise<void>((resolve) => {
115	      setTimeout(resolve, timeoutMs);
116	    });
117	
118	    // Create subscription promise
119	    const subscriptionPromise = new Promise<void>((resolve) => {
120	      let completed = 0;
121	
122	      for (const relay of relays) {
123	        relaysQueried.push(relay);
124	
125	        const sub = pool.subscribeMany(
126	          [relay],
127	          [
128	            {
129	              kinds: [0],
130	              authors: [pubkey],
131	              limit: 1,
132	            },
133	          ] as unknown as Parameters<typeof pool.subscribeMany>[1],
134	          {
135	            onevent(event) {
136	              events.push({ event, relay });
137	            },
138	            oneose() {
139	              completed++;
140	              if (completed >= relays.length) {
141	                resolve();
142	              }
143	            },
144	            onclose() {
145	              completed++;
146	              if (completed >= relays.length) {
147	                resolve();
148	              }
149	            },
150	          },
151	        );
152	
153	        // Clean up subscription after timeout
154	        setTimeout(() => {
155	          sub.close();
156	        }, timeoutMs);
157	      }
158	    });
159	
160	    // Wait for either all relays to respond or timeout
161	    await Promise.race([subscriptionPromise, timeoutPromise]);
162	
163	    // No events found
164	    if (events.length === 0) {
165	      return {
166	        ok: false,
167	        error: "No profile found on any relay",
168	        relaysQueried,
169	      };
170	    }
171	
172	    // Find the event with the highest created_at (newest wins for replaceable events)
173	    let bestEvent: { event: Event; relay: string } | null = null;
174	    for (const item of events) {
175	      if (!bestEvent || item.event.created_at > bestEvent.event.created_at) {
176	        bestEvent = item;
177	      }
178	    }
179	
180	    if (!bestEvent) {
181	      return {
182	        ok: false,
183	        error: "No valid profile event found",
184	        relaysQueried,
185	      };
186	    }
187	
188	    // Verify the event signature
189	    const isValid = verifyEvent(bestEvent.event);
190	    if (!isValid) {
191	      return {
192	        ok: false,
193	        error: "Profile event has invalid signature",
194	        relaysQueried,
195	        sourceRelay: bestEvent.relay,
196	      };
197	    }
198	
199	    // Parse the profile content
200	    let content: ProfileContent;
201	    try {
202	      content = JSON.parse(bestEvent.event.content) as ProfileContent;
203	    } catch {
204	      return {
205	        ok: false,
206	        error: "Profile event has invalid JSON content",
207	        relaysQueried,
208	        sourceRelay: bestEvent.relay,
209	      };
210	    }
211	
212	    // Convert to our profile format
213	    const profile = contentToProfile(content);
214	
215	    // Sanitize URLs from imported profile to prevent SSRF when auto-merging
216	    const sanitizedProfile = sanitizeProfileUrls(profile);
217	
218	    return {
219	      ok: true,
220	      profile: sanitizedProfile,
221	      event: {
222	        id: bestEvent.event.id,
223	        pubkey: bestEvent.event.pubkey,
224	        created_at: bestEvent.event.created_at,
225	      },
226	      relaysQueried,
227	      sourceRelay: bestEvent.relay,
228	    };
229	  } finally {
230	    pool.close(relays);
231	  }
232	}
233	
234	/**
235	 * Merge imported profile with local profile.
236	 *
237	 * Strategy:
238	 * - For each field, prefer local if set, otherwise use imported
239	 * - This preserves user customizations while filling in missing data
240	 */
241	export function mergeProfiles(
242	  local: NostrProfile | undefined,
243	  imported: NostrProfile | undefined,
244	): NostrProfile {
245	  if (!imported) {
246	    return local ?? {};
247	  }
248	  if (!local) {
249	    return imported;
250	  }
251	
252	  return {
253	    name: local.name ?? imported.name,
254	    displayName: local.displayName ?? imported.displayName,
255	    about: local.about ?? imported.about,
256	    picture: local.picture ?? imported.picture,
257	    banner: local.banner ?? imported.banner,
258	    website: local.website ?? imported.website,
259	    nip05: local.nip05 ?? imported.nip05,
260	    lud16: local.lud16 ?? imported.lud16,
261	  };
262	}
