15	async function withTempStateDir<T>(fn: (dir: string) => Promise<T>) {
16	  const previous = process.env.OPENCLAW_STATE_DIR;
17	  const dir = await fs.mkdtemp(path.join(os.tmpdir(), "openclaw-nostr-"));
18	  process.env.OPENCLAW_STATE_DIR = dir;
19	  setNostrRuntime({
20	    state: {
