29	      },
30	    },
31	  } as PluginRuntime);
32	  try {
33	    return await fn(dir);
34	  } finally {
35	    if (previous === undefined) {
36	      delete process.env.OPENCLAW_STATE_DIR;
37	    } else {
38	      process.env.OPENCLAW_STATE_DIR = previous;
39	    }
