```

---

### `src/` implementation files

#### `extensions/pulseboard/src/types.ts`
Defines TypeScript interfaces. Imports types from `./runtime-api.js`.

Key types:
```ts
// Per-board group config (mirrors IrcChannelConfig)
export type PulseboardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Top-level account config
export type PulseboardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiUrl?: string;       // default wss://boards.pulseboard.io/ws
  apiToken?: string;     // bearer token
  userId?: string;       // self identity on PulseBoard
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  boardPolicy?: GroupPolicy;
  boardAllowFrom?: Array<string | number>;
  boards?: Record<string, PulseboardBoardConfig>;
  markdown?: MarkdownConfig;
  textChunkLimit?: number;
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  responsePrefix?: string;
  mediaMaxMb?: number;
  ...ReplyRuntimeConfig shape fields;
};

export type PulseboardConfig = PulseboardAccountConfig & {
  accounts?: Record<string, PulseboardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseboardConfig;
  };
};

// Inbound message from the PulseBoard WebSocket
export type PulseboardInboundMessage = {
  messageId: string;
  target: string;          // board name (~general) or sender userId
  senderUserId: string;
  senderDisplayName?: string;
  text: string;
  timestamp: number;
  isBoard: boolean;        // true = group/board, false = DM
};

export type PulseboardProbe = BaseProbeResult<string> & {
  apiUrl: string;
  userId: string;
  latencyMs?: number;
};
```

#### `extensions/pulseboard/src/config-schema.ts`
Imports from `openclaw/plugin-sdk/channel-config-schema` and `openclaw/plugin-sdk/zod`.

