export async function monitorPulseboardProvider(opts: {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (...) => void;
  onMessage?: (msg: PulseboardInboundMessage) => void | Promise<void>;
}): Promise<{ stop: () => void }>
```
- Resolves account; throws if unconfigured
- Calls `connectPulseboardClient({ ..., boards: account.config.boards (keys), abortSignal, onMessage })`
- In `onMessage`: filters self messages (sender === account.userId), records inbound activity, calls `handlePulseboardInbound` (unless `opts.onMessage` overrides for tests)
- Returns `{ stop: () => client.disconnect("shutdown") }`

