// Import schema builders and validators
import { buildChannelConfigSchema, DmPolicySchema, ... } from "openclaw/plugin-sdk/...";
import { z } from "openclaw/plugin-sdk/zod";

// Define account-level schema (used for per-account config)
export const ChannelAccountSchema = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  privateKey: buildSecretInputSchema().optional(),  // For secrets
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  // ... other fields
}).strict();

// Define top-level schema (wrapper that includes accounts)
export const ChannelConfigSchema = ChannelAccountSchema.extend({
  accounts: z.record(z.string(), ChannelAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
});

// Add custom validation
.superRefine((value, ctx) => {
  // Custom checks
});

// Export with UI hints
export const channelChannelConfigSchema = buildChannelConfigSchema(ChannelConfigSchema, {
  uiHints: channelConfigUiHints,
});

