```ts
export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount, PulseboardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: { ...getChatChannelMeta("pulseboard"), quickstartAllowFrom: true },
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        media: true,
        blockStreaming: true,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseboardChannelConfigSchema,
      config: {
        ...pulseboardConfigAdapter,     // createScopedChannelConfigAdapter
        isConfigured: (account) => account.configured,
        describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured, extra: { apiUrl: account.apiUrl, userId: account.userId } }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => /* resolve board requireMention */,
        resolveToolPolicy: ({ cfg, accountId, groupId }) => /* resolve board tool policy */,
      },
      messaging: {
        normalizeTarget: normalizePulseboardMessagingTarget,
        targetResolver: { looksLikeId: looksLikePulseboardTargetId, hint: "<~board|userId>" },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => /* map to board or user targets */,
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => /* from allowFrom config */,
        listGroups: async (params) => /* from boards config */,
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseboardAccount, PulseboardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          apiUrl: account.apiUrl,
          userId: account.userId,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseboard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: { apiUrl: account.apiUrl, userId: account.userId },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          /* throw if unconfigured */
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              monitorPulseboardProvider({
                accountId: ctx.account.accountId,
                config: ctx.cfg as CoreConfig,
                runtime: ctx.runtime,
                abortSignal: ctx.abortSignal,
                statusSink: createAccountStatusSink({ accountId: ctx.accountId, setStatus: ctx.setStatus }),
              }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: (entry) => normalizePulseboardAllowEntry(entry),
        notify: async ({ id, message }) => {
          const target = id.trim();
          if (!target) throw new Error(`invalid PulseBoard pairing id: ${id}`);
          await sendMessagePulseboard(target, message);
        },
      },
    },
    security: {
      resolveDmPolicy: createScopedDmSecurityResolver<ResolvedPulseboardAccount>({ ... }),
      collectWarnings: composeAccountWarningCollectors<...>(
        createAllowlistProviderOpenWarningCollector<...>({
          providerConfigPresent: (cfg) => cfg.channels?.pulseboard !== undefined,
          resolveGroupPolicy: (account) => account.config.boardPolicy,
          buildOpenWarning: {
            surface: "PulseBoard boards",
            openBehavior: "allows all boards and senders (mention-gated)",
            remediation: 'Prefer channels.pulseboard.boardPolicy="allowlist" with channels.pulseboard.boards',
          },
        }),
      ),
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        textChunkLimit: 4000,   // PulseBoard's 4 000-char limit
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          sendMessagePulseboard(to, text, { cfg: cfg as CoreConfig, accountId, replyTo: replyToId }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          sendMessagePulseboard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            { cfg: cfg as CoreConfig, accountId, replyTo: replyToId }),
      },
    },
  });
```

---

### Test files

#### `extensions/pulseboard/src/channel.test.ts`
Mirrors `extensions/irc/src/channel.test.ts`. Tests:
- `pulseboardPlugin.outbound?.chunker` works without runtime initialization
- `pulseboardPlugin.outbound?.textChunkLimit === 4000`
- `pulseboardPlugin.capabilities.chatTypes` includes `"direct"` and `"group"`

#### `extensions/pulseboard/src/normalize.test.ts`
Tests:
- `normalizePulseboardMessagingTarget("~general")` → `"~general"`
- `normalizePulseboardMessagingTarget("board:general")` → `"~general"`
- `normalizePulseboardMessagingTarget("user:alice")` → `"alice"`
- `normalizePulseboardMessagingTarget("pulseboard:alice")` → `"alice"`
- `normalizePulseboardMessagingTarget("")` → `undefined`
- `isBoardTarget("~general")` → `true`, `isBoardTarget("alice")` → `false`
- `normalizePulseboardAllowEntry("user:ALICE")` → `"alice"`

#### `extensions/pulseboard/src/accounts.test.ts`
Tests:
- `resolveAccount` returns `configured: false` when apiToken/userId missing
- `resolveAccount` returns `configured: true` when apiToken + userId present
- `resolveAccount` reads `PULSEBOARD_API_TOKEN` env var for default account
- Default `apiUrl` falls back to `"wss://boards.pulseboard.io/ws"`

#### `extensions/pulseboard/src/config-schema.test.ts`
Tests:
- Valid config parses correctly
- `dmPolicy="open"` without `allowFrom: ["*"]` fails validation
- `PulseboardChannelConfigSchema` has `uiHints` set

---

## Implementation Order

1. **Root files** — `openclaw.plugin.json`, `package.json`, `index.ts`, `setup-entry.ts`, `api.ts`, `channel-config-api.ts`
2. **Foundational src** — `types.ts`, `config-ui-hints.ts`, `runtime-api.ts`, `runtime.ts`
3. **Config** — `config-schema.ts` (imports `config-ui-hints.ts`)
4. **Accounts** — `accounts.ts` (imports `types.ts`, `runtime-api.ts`)
5. **Utilities** — `normalize.ts`
6. **Client** — `client.ts` (fictional WebSocket client)
7. **Probe** — `probe.ts`
8. **Send** — `send.ts`
9. **Inbound** — `inbound.ts` (most complex)
10. **Monitor** — `monitor.ts`
11. **Setup** — `setup-core.ts`, `setup-surface.ts`
12. **Channel** — `channel.ts` (assembles everything)
13. **Tests** — `channel.test.ts`, `normalize.test.ts`, `accounts.test.ts`, `config-schema.test.ts`

---

## Verification

After implementation:

1. **Type check (scoped):**
   ```sh
   cd extensions/pulseboard && pnpm exec tsc --noEmit
   ```
   or from repo root:
   ```sh
   pnpm tsgo
   ```

2. **Lint/format:**
   ```sh
   pnpm check
   ```

3. **Tests (scoped):**
   ```sh
   pnpm test -- extensions/pulseboard
   ```

4. **Spot-check plugin discovery:**
   ```sh
   pnpm openclaw plugins list
   # should include pulseboard
   ```

5. **Setup wizard dry-run:**
   ```sh
   pnpm openclaw setup pulseboard --dry-run
   ```

