// Private runtime barrel for the bundled PulseBoard extension.
// Keep this barrel thin and aligned with the local extension surface.
//
// Note: unlike other bundled channel plugins, PulseBoard does not have a
// dedicated `openclaw/plugin-sdk/pulseboard` facade (that would require a
// matching src/plugin-sdk/pulseboard.ts in core). Instead we aggregate the
// needed symbols from the available generic public SDK paths.

export { logInboundDrop } from "openclaw/plugin-sdk/channel-inbound";
export { createAccountStatusSink } from "openclaw/plugin-sdk/channel-lifecycle";
export { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
export { createChannelReplyPipeline } from "openclaw/plugin-sdk/channel-reply-pipeline";
export type { BaseProbeResult } from "openclaw/plugin-sdk/channel-runtime";
export { PAIRING_APPROVED_MESSAGE } from "openclaw/plugin-sdk/channel-status";
export { resolveControlCommandGate } from "openclaw/plugin-sdk/compat";
export type {
  BlockStreamingCoalesceConfig,
  DmConfig,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  MarkdownConfig,
} from "openclaw/plugin-sdk/config-runtime";
export {
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
} from "openclaw/plugin-sdk/core";
export type {
  ChannelPlugin,
  OpenClawConfig,
  PluginRuntime,
} from "openclaw/plugin-sdk/core";
export { isDangerousNameMatchingEnabled } from "openclaw/plugin-sdk/dangerous-name-runtime";
export {
  createNormalizedOutboundDeliverer,
  deliverFormattedTextWithAttachments,
} from "openclaw/plugin-sdk/reply-payload";
export type { OutboundReplyPayload } from "openclaw/plugin-sdk/reply-payload";
export {
  GROUP_POLICY_BLOCKED_LABEL,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  warnMissingProviderGroupPolicyFallbackOnce,
} from "openclaw/plugin-sdk/runtime-group-policy";
export type { RuntimeEnv } from "openclaw/plugin-sdk/runtime-env";
export {
  readStoreAllowFromForDmPolicy,
  resolveEffectiveAllowFromLists,
} from "openclaw/plugin-sdk/security-runtime";
export { buildBaseChannelStatusSummary } from "openclaw/plugin-sdk/status-helpers";

/** Chunk outbound text for PulseBoard, preferring newline then space boundaries. */
export function chunkTextForOutbound(text: string, limit: number): string[] {
  if (text.length <= limit) return [text];
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > limit) {
    const window = remaining.slice(0, limit);
    const lastNewline = window.lastIndexOf("\n");
    const lastSpace = window.lastIndexOf(" ");
    const breakAt = lastNewline > 0 ? lastNewline : lastSpace > 0 ? lastSpace : limit;
    chunks.push(remaining.slice(0, breakAt));
    // skip the break character unless we hard-broke at limit
    remaining = remaining.slice(breakAt === limit ? breakAt : breakAt + 1);
  }
  if (remaining.length > 0) chunks.push(remaining);
  return chunks;
}

