import type {
  BaseProbeResult,
  BlockStreamingCoalesceConfig,
  DmConfig,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

/** Per-board (group) access and policy configuration. */
export type PulseboardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

/** Top-level account configuration for a PulseBoard identity. */
export type PulseboardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** WebSocket URL (default: wss://boards.pulseboard.io/ws) */
  apiUrl?: string;
  /** PulseBoard API bearer token */
  apiToken?: string;
  /** Your PulseBoard user ID */
  userId?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  boardPolicy?: GroupPolicy;
  boardAllowFrom?: Array<string | number>;
  /** Named boards to monitor (keys are board names like "~general") */
  boards?: Record<string, PulseboardBoardConfig>;
  markdown?: MarkdownConfig;
  textChunkLimit?: number;
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  responsePrefix?: string;
  mediaMaxMb?: number;
  dms?: Record<string, DmConfig>;
  mentionPatterns?: string[];
};

/** Root config section supporting multiple named accounts. */
export type PulseboardConfig = PulseboardAccountConfig & {
  accounts?: Record<string, PulseboardAccountConfig>;
  defaultAccount?: string;
};

/** OpenClaw config augmented with the PulseBoard channel section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseboardConfig;
  };
};

/** An inbound message received from the PulseBoard WebSocket. */
export type PulseboardInboundMessage = {
  messageId: string;
  /** Board name (e.g. "~general") for board messages, or sender user ID for DMs. */
  target: string;
  senderUserId: string;
  senderDisplayName?: string;
  text: string;
  timestamp: number;
  /** true = board/group message, false = direct message */
  isBoard: boolean;
};

/** Result of a PulseBoard connectivity probe. */
export type PulseboardProbe = BaseProbeResult<string> & {
  apiUrl: string;
  userId: string;
  latencyMs?: number;
};

