import type { PulseboardInboundMessage } from "./types.js";

const PULSEBOARD_TARGET_PATTERN = /^[^\s\x00-\x1f\x7f]+$/u;

/** Returns true if the target is a board (group) rather than a direct-message user ID. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("~");
}

/**
 * Normalise a raw messaging target string to a canonical PulseBoard target.
 * Handles:
 *   - "pulseboard:<target>" prefix stripping
 *   - "board:<name>" → "~<name>"
 *   - "user:<id>" prefix stripping
 *   - Bare board names without "~" are left as-is (assumed user IDs)
 * Returns undefined for empty or structurally invalid targets.
 */
export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  const lowered = target.toLowerCase();

  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  if (target.toLowerCase().startsWith("board:")) {
    const rest = target.slice("board:".length).trim();
    target = rest.startsWith("~") ? rest : `~${rest}`;
  } else if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseboardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Returns true if the string looks like a valid PulseBoard target ID (no whitespace / control chars). */
export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalise a single allowlist entry for PulseBoard.
 * Strips known prefixes and lower-cases.
 */
export function normalizePulseboardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/** Normalise an array of allowlist entries, dropping empties. */
export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseboardAllowEntry(String(entry))).filter(Boolean);
}

/**
 * Build allowlist match candidates for an inbound PulseBoard message.
 * Returns the userId and its lower-cased form.
 */
export function buildPulseboardAllowlistCandidates(message: PulseboardInboundMessage): string[] {
  const userId = message.senderUserId.trim();
  if (!userId) {
    return [];
  }
  const lower = userId.toLowerCase();
  const candidates = new Set<string>();
  candidates.add(userId);
  candidates.add(lower);
  return [...candidates];
}

/**
 * Resolve whether an inbound PulseBoard message is allowed by the given allowFrom list.
 * Supports wildcard "*" and exact user ID matching (case-insensitive).
 */
export function resolvePulseboardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseboardInboundMessage;
}): { allowed: boolean; source?: string } {
  const allowSet = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowSet.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseboardAllowlistCandidates(params.message);
  for (const candidate of candidates) {
    if (allowSet.has(candidate.toLowerCase())) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

