// Fictional PulseBoard WebSocket client.
// Uses the Node 22+ built-in WebSocket global — no external npm dependency.

import { isBoardTarget } from "./normalize.js";
import type { PulseboardInboundMessage } from "./types.js";

export type PulseboardClientOptions = {
  apiUrl: string;
  apiToken: string;
  userId: string;
  /** Board names to subscribe to on connect (e.g. ["~general", "~ops"]). */
  boards?: string[];
  abortSignal?: AbortSignal;
  connectTimeoutMs?: number;
  onMessage?: (msg: PulseboardInboundMessage) => void | Promise<void>;
  onError?: (err: Error) => void;
  onDisconnect?: () => void;
};

export type PulseboardClient = {
  /** Send a message to a board or user. */
  sendMessage(target: string, text: string): void;
  isReady(): boolean;
  disconnect(reason?: string): void;
  readonly userId: string;
};

type PulseboardWireFrame =
  | { type: "auth"; token: string; userId: string }
  | { type: "subscribe"; boards: string[] }
  | { type: "send"; to: string; body: string }
  | { type: "ping" }
  | { type: "auth_ok" }
  | { type: "auth_error"; message?: string }
  | { type: "message"; msgId: string; from: string; target: string; body: string; ts: number };

/**
 * Open a PulseBoard WebSocket connection.
 * Resolves once the auth handshake completes and the client is ready to send/receive.
 */
export async function connectPulseboardClient(
  opts: PulseboardClientOptions,
): Promise<PulseboardClient> {
  return new Promise<PulseboardClient>((resolve, reject) => {
    const connectTimeout = setTimeout(() => {
      reject(new Error(`PulseBoard connect timeout after ${opts.connectTimeoutMs ?? 15000}ms`));
      ws.close();
    }, opts.connectTimeoutMs ?? 15000);

    const ws = new WebSocket(opts.apiUrl);
    let ready = false;

    if (opts.abortSignal) {
      opts.abortSignal.addEventListener("abort", () => {
        ws.close(1000, "aborted");
      });
    }

    ws.addEventListener("open", () => {
      // Send auth frame immediately on open
      const authFrame: PulseboardWireFrame = {
        type: "auth",
        token: opts.apiToken,
        userId: opts.userId,
      };
      ws.send(JSON.stringify(authFrame));
    });

    ws.addEventListener("message", (event: MessageEvent) => {
      let frame: PulseboardWireFrame;
      try {
        frame = JSON.parse(String(event.data)) as PulseboardWireFrame;
      } catch {
        return;
      }

      if (frame.type === "auth_ok") {
        clearTimeout(connectTimeout);
        ready = true;

        // Subscribe to any configured boards
        if (opts.boards && opts.boards.length > 0) {
          const subscribeFrame: PulseboardWireFrame = { type: "subscribe", boards: opts.boards };
          ws.send(JSON.stringify(subscribeFrame));
        }

        resolve(client);
        return;
      }

      if (frame.type === "auth_error") {
        clearTimeout(connectTimeout);
        const msg = (frame as { type: "auth_error"; message?: string }).message ?? "auth failed";
        reject(new Error(`PulseBoard auth error: ${msg}`));
        ws.close();
        return;
      }

      if (frame.type === "message") {
        const msgFrame = frame as {
          type: "message";
          msgId: string;
          from: string;
          target: string;
          body: string;
          ts: number;
        };
        const isBoard = isBoardTarget(msgFrame.target);
        const inbound: PulseboardInboundMessage = {
          messageId: msgFrame.msgId,
          target: msgFrame.target,
          senderUserId: msgFrame.from,
          text: msgFrame.body,
          timestamp: msgFrame.ts ?? Date.now(),
          isBoard,
        };
        if (opts.onMessage) {
          void Promise.resolve(opts.onMessage(inbound));
        }
      }
    });

    ws.addEventListener("error", () => {
      const err = new Error("PulseBoard WebSocket error");
      if (!ready) {
        clearTimeout(connectTimeout);
        reject(err);
      } else {
        opts.onError?.(err);
      }
    });

    ws.addEventListener("close", () => {
      if (!ready) {
        clearTimeout(connectTimeout);
        reject(new Error("PulseBoard WebSocket closed before auth completed"));
      } else {
        opts.onDisconnect?.();
      }
    });

    const client: PulseboardClient = {
      get userId() {
        return opts.userId;
      },
      sendMessage(target: string, text: string): void {
        if (ws.readyState !== WebSocket.OPEN) {
          throw new Error("PulseBoard WebSocket is not open");
        }
        const frame: PulseboardWireFrame = { type: "send", to: target, body: text };
        ws.send(JSON.stringify(frame));
      },
      isReady(): boolean {
        return ready && ws.readyState === WebSocket.OPEN;
      },
      disconnect(reason?: string): void {
        ready = false;
        ws.close(1000, reason ?? "disconnect");
      },
    };
  });
}

/**
 * Open a transient PulseBoard connection for connectivity probing.
 * Resolves with the connect latency (ms) on success; disconnects immediately after auth.
 */
export async function connectPulseboardForProbe(opts: {
  apiUrl: string;
  apiToken: string;
  userId: string;
  timeoutMs?: number;
}): Promise<{ latencyMs: number }> {
  const start = Date.now();
  const client = await connectPulseboardClient({
    apiUrl: opts.apiUrl,
    apiToken: opts.apiToken,
    userId: opts.userId,
    connectTimeoutMs: opts.timeoutMs ?? 15000,
  });
  const latencyMs = Date.now() - start;
  client.disconnect("probe");
  return { latencyMs };
}

