      const authFrame: PulseboardWireFrame = {
        type: "auth",
        token: opts.apiToken,
        userId: opts.userId,
      };
      ws.send(JSON.stringify(authFrame));
    });

    ws.addEventListener("message", (event: MessageEvent) => {
      let frame: PulseboardWireFrame;
      try {
        frame = JSON.parse(String(event.data)) as PulseboardWireFrame;
      } catch {
        return;
      }

      if (frame.type === "auth_ok") {
        clearTimeout(connectTimeout);
        ready = true;

        // Subscribe to any configured boards
        if (opts.boards && opts.boards.length > 0) {
          const subscribeFrame: PulseboardWireFrame = { type: "subscribe", boards: opts.boards };
          ws.send(JSON.stringify(subscribeFrame));
        }

        resolve(client);
        return;
      }

      if (frame.type === "auth_error") {
        clearTimeout(connectTimeout);
        const msg = (frame as { type: "auth_error"; message?: string }).message ?? "auth failed";
        reject(new Error(`PulseBoard auth error: ${msg}`));
        ws.close();
        return;
      }

      if (frame.type === "message") {
        const msgFrame = frame as {
          type: "message";
          msgId: string;
          from: string;
          target: string;
          body: string;
          ts: number;
        };
        const isBoard = isBoardTarget(msgFrame.target);
        const inbound: PulseboardInboundMessage = {
          messageId: msgFrame.msgId,
          target: msgFrame.target,
          senderUserId: msgFrame.from,
          text: msgFrame.body,
          timestamp: msgFrame.ts ?? Date.now(),
          isBoard,
        };
        if (opts.onMessage) {
          void Promise.resolve(opts.onMessage(inbound));
        }
      }
    });

    ws.addEventListener("error", () => {
      const err = new Error("PulseBoard WebSocket error");
      if (!ready) {
        clearTimeout(connectTimeout);
        reject(err);
      } else {
        opts.onError?.(err);
      }
    });

    ws.addEventListener("close", () => {
      if (!ready) {
        clearTimeout(connectTimeout);
        reject(new Error("PulseBoard WebSocket closed before auth completed"));
      } else {
        opts.onDisconnect?.();
      }
    });

    const client: PulseboardClient = {
      get userId() {
        return opts.userId;
      },
      sendMessage(target: string, text: string): void {
        if (ws.readyState !== WebSocket.OPEN) {
          throw new Error("PulseBoard WebSocket is not open");
        }
        const frame: PulseboardWireFrame = { type: "send", to: target, body: text };
        ws.send(JSON.stringify(frame));
      },
      isReady(): boolean {
        return ready && ws.readyState === WebSocket.OPEN;
      },
      disconnect(reason?: string): void {
        ready = false;
        ws.close(1000, reason ?? "disconnect");
      },
    };
  });
}

/**
 * Open a transient PulseBoard connection for connectivity probing.
 * Resolves with the connect latency (ms) on success; disconnects immediately after auth.
 */
export async function connectPulseboardForProbe(opts: {
  apiUrl: string;
  apiToken: string;
  userId: string;
  timeoutMs?: number;
}): Promise<{ latencyMs: number }> {
  const start = Date.now();
  const client = await connectPulseboardClient({
    apiUrl: opts.apiUrl,
    apiToken: opts.apiToken,
    userId: opts.userId,
    connectTimeoutMs: opts.timeoutMs ?? 15000,
  });
  const latencyMs = Date.now() - start;
  client.disconnect("probe");
  return { latencyMs };
}

