import { resolvePulseboardAccount } from "./accounts.js";
import { connectPulseboardForProbe } from "./client.js";
import type { BaseProbeResult } from "./runtime-api.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";

export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });

  const base: BaseProbeResult<string> = {
    ok: false,
    error: undefined,
    value: undefined,
  };

  if (!account.configured) {
    return {
      ...base,
      ok: false,
      error: "PulseBoard is not configured (missing apiToken or userId)",
      apiUrl: account.apiUrl,
      userId: account.userId,
    };
  }

  try {
    const { latencyMs } = await connectPulseboardForProbe({
      apiUrl: account.apiUrl,
      apiToken: account.apiToken,
      userId: account.userId,
      timeoutMs: opts?.timeoutMs ?? 15000,
    });
    return {
      ok: true,
      value: account.userId,
      error: undefined,
      apiUrl: account.apiUrl,
      userId: account.userId,
      latencyMs,
    };
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    return {
      ok: false,
      error: message,
      value: undefined,
      apiUrl: account.apiUrl,
      userId: account.userId,
    };
  }
}

