  statusSink?: (patch: { lastOutboundAt?: number }) => void;
}): Promise<void> {
  const delivered = await deliverFormattedTextWithAttachments({
    payload: params.payload,
    send: async ({ text, replyToId }) => {
      if (params.sendReply) {
        await params.sendReply(params.target, text, replyToId);
      } else {
        await sendMessagePulseboard(params.target, text, {
          accountId: params.accountId,
          replyTo: replyToId,
        });
      }
      params.statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
  if (!delivered) {
    return;
  }
}

/** Inline equivalent of dispatchInboundReplyWithBase using generic SDK primitives. */
async function dispatchPulseboardInboundReply(params: {
  cfg: OpenClawConfig;
  channel: string;
  accountId?: string;
  route: { agentId: string; sessionKey: string };
  storePath: string;
  ctxPayload: ReturnType<typeof import("./runtime.js").getPulseboardRuntime>["channel"]["reply"]["finalizeInboundContext"] extends (...args: unknown[]) => infer R ? R : never;
  core: ReturnType<typeof getPulseboardRuntime>;
  deliver: (payload: OutboundReplyPayload) => Promise<void>;
  onRecordError: (err: unknown) => void;
  onDispatchError: (err: unknown, info: { kind: string }) => void;
  replyOptions?: {
    skillFilter?: string[];
    disableBlockStreaming?: boolean;
  };
}): Promise<void> {
  await params.core.channel.session.recordInboundSession({
    storePath: params.storePath,
    sessionKey: params.ctxPayload.SessionKey ?? params.route.sessionKey,
    ctx: params.ctxPayload,
