            direction: "outbound",
          });
        },
        statusSink: opts.statusSink,
      });
    },
    onError: (err) => {
      logger.error(`[${account.accountId}] PulseBoard error: ${err.message}`);
    },
    onDisconnect: () => {
      logger.info(`[${account.accountId}] PulseBoard disconnected`);
    },
  });

  logger.info(
    `[${account.accountId}] connected to PulseBoard (${account.apiUrl}) as ${account.userId}`,
  );

  return {
    stop: () => {
      client?.disconnect("shutdown");
      client = null;
    },
  };
}

