import { describe, expect, it } from "vitest";
import { pulseboardPlugin } from "./channel.js";

describe("pulseboardPlugin", () => {
  it("has textChunkLimit of 4000", () => {
    expect(pulseboardPlugin.outbound?.base?.textChunkLimit).toBe(4000);
  });

  it("includes both direct and group chatTypes", () => {
    const chatTypes = pulseboardPlugin.capabilities?.chatTypes ?? [];
    expect(chatTypes).toContain("direct");
    expect(chatTypes).toContain("group");
  });

  it("chunker works without runtime initialization", () => {
    const chunker = pulseboardPlugin.outbound?.base?.chunker;
    expect(typeof chunker).toBe("function");
    if (typeof chunker === "function") {
      const result = chunker("hello world", 4000);
      expect(result).toEqual(["hello world"]);
    }
  });

  it("chunker splits long text at word boundaries", () => {
    const chunker = pulseboardPlugin.outbound?.base?.chunker;
    if (typeof chunker !== "function") {
      return;
    }
    const longText = "word ".repeat(1000).trimEnd();
    const chunks = chunker(longText, 100);
    expect(chunks.length).toBeGreaterThan(1);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(100);
    }
    // Reassembling chunks (rejoining with space) should recover all words
    const reconstructed = chunks.join(" ");
    expect(reconstructed).toBe(longText);
  });

  it("has plugin id pulseboard", () => {
    expect(pulseboardPlugin.id).toBe("pulseboard");
  });

  it("supports blockStreaming capability", () => {
    expect(pulseboardPlugin.capabilities?.blockStreaming).toBe(true);
  });
});

