} from "./normalize.js";
import type { PulseboardInboundMessage } from "./types.js";

function makeMessage(senderUserId: string): PulseboardInboundMessage {
  return {
    messageId: "msg1",
    target: "~general",
    senderUserId,
    text: "hello",
    timestamp: Date.now(),
    isBoard: true,
  };
}

describe("isBoardTarget", () => {
  it("returns true for board targets prefixed with ~", () => {
    expect(isBoardTarget("~general")).toBe(true);
