import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { resolvePulseboardAccount } from "./accounts.js";
import type { CoreConfig } from "./types.js";

const BASE_CFG: CoreConfig = {};

const CONFIGURED_CFG: CoreConfig = {
  channels: {
    pulseboard: {
      apiToken: "pb_live_testtoken",
      userId: "alice123",
    },
  },
};

describe("resolvePulseboardAccount", () => {
  describe("when no config is provided", () => {
    it("returns configured=false when apiToken and userId are missing", () => {
      const account = resolvePulseboardAccount({ cfg: BASE_CFG });
      expect(account.configured).toBe(false);
    });

    it("falls back to default apiUrl", () => {
      const account = resolvePulseboardAccount({ cfg: BASE_CFG });
      expect(account.apiUrl).toBe("wss://boards.pulseboard.io/ws");
    });
  });

  describe("when config has apiToken and userId", () => {
    it("returns configured=true", () => {
      const account = resolvePulseboardAccount({ cfg: CONFIGURED_CFG });
      expect(account.configured).toBe(true);
    });

    it("resolves apiToken and userId from config", () => {
      const account = resolvePulseboardAccount({ cfg: CONFIGURED_CFG });
      expect(account.apiToken).toBe("pb_live_testtoken");
      expect(account.userId).toBe("alice123");
    });
  });

  describe("env var support for default account", () => {
    const originalToken = process.env.PULSEBOARD_API_TOKEN;
    const originalUserId = process.env.PULSEBOARD_USER_ID;
    const originalUrl = process.env.PULSEBOARD_API_URL;

    beforeEach(() => {
      delete process.env.PULSEBOARD_API_TOKEN;
      delete process.env.PULSEBOARD_USER_ID;
      delete process.env.PULSEBOARD_API_URL;
    });

    afterEach(() => {
      if (originalToken !== undefined) {
        process.env.PULSEBOARD_API_TOKEN = originalToken;
      } else {
        delete process.env.PULSEBOARD_API_TOKEN;
      }
      if (originalUserId !== undefined) {
        process.env.PULSEBOARD_USER_ID = originalUserId;
      } else {
        delete process.env.PULSEBOARD_USER_ID;
      }
      if (originalUrl !== undefined) {
        process.env.PULSEBOARD_API_URL = originalUrl;
      } else {
        delete process.env.PULSEBOARD_API_URL;
      }
    });

    it("reads PULSEBOARD_API_TOKEN for default account", () => {
      process.env.PULSEBOARD_API_TOKEN = "env_token_abc";
      process.env.PULSEBOARD_USER_ID = "env_user";
      const account = resolvePulseboardAccount({ cfg: BASE_CFG });
      expect(account.apiToken).toBe("env_token_abc");
      expect(account.configured).toBe(true);
    });

    it("reads PULSEBOARD_USER_ID for default account", () => {
      process.env.PULSEBOARD_API_TOKEN = "env_token_abc";
      process.env.PULSEBOARD_USER_ID = "env_user_123";
      const account = resolvePulseboardAccount({ cfg: BASE_CFG });
      expect(account.userId).toBe("env_user_123");
    });

    it("reads PULSEBOARD_API_URL for default account", () => {
      process.env.PULSEBOARD_API_URL = "wss://custom.example.com/ws";
      const account = resolvePulseboardAccount({ cfg: BASE_CFG });
      expect(account.apiUrl).toBe("wss://custom.example.com/ws");
    });

    it("env token takes precedence over config for default account", () => {
      process.env.PULSEBOARD_API_TOKEN = "env_overrides";
      const account = resolvePulseboardAccount({ cfg: CONFIGURED_CFG });
      expect(account.apiToken).toBe("env_overrides");
    });
  });

  describe("configured field", () => {
    it("is false when only apiToken is set", () => {
      const cfg: CoreConfig = {
        channels: {
          pulseboard: { apiToken: "tok" },
        },
      };
      const account = resolvePulseboardAccount({ cfg });
      expect(account.configured).toBe(false);
    });

    it("is false when only userId is set", () => {
      const cfg: CoreConfig = {
        channels: {
          pulseboard: { userId: "alice" },
        },
      };
      const account = resolvePulseboardAccount({ cfg });
      expect(account.configured).toBe(false);
    });

    it("is true when both apiToken and userId are set", () => {
      const account = resolvePulseboardAccount({ cfg: CONFIGURED_CFG });
      expect(account.configured).toBe(true);
    });
  });
});

