import { describe, expect, it } from "vitest";
import {
  PulseboardAccountSchema,
  PulseboardAccountSchemaBase,
  PulseboardChannelConfigSchema,
  PulseboardConfigSchema,
} from "./config-schema.js";

describe("PulseboardAccountSchemaBase", () => {
  it("parses valid minimal config", () => {
    const result = PulseboardAccountSchemaBase.safeParse({});
    expect(result.success).toBe(true);
  });

  it("parses full config with all fields", () => {
    const result = PulseboardAccountSchemaBase.safeParse({
      name: "My PulseBoard",
      enabled: true,
      apiUrl: "wss://boards.pulseboard.io/ws",
      apiToken: "pb_live_abc",
      userId: "alice123",
      dmPolicy: "pairing",
      boardPolicy: "allowlist",
      boards: {
        "~general": { requireMention: true },
      },
      allowFrom: ["bob"],
      boardAllowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });

  it("rejects invalid apiUrl", () => {
    const result = PulseboardAccountSchemaBase.safeParse({ apiUrl: "not-a-url" });
    expect(result.success).toBe(false);
  });
});

describe("PulseboardAccountSchema", () => {
  it('requires allowFrom to include "*" when dmPolicy="open"', () => {
    const result = PulseboardAccountSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["alice"],
    });
    expect(result.success).toBe(false);
  });

  it('passes when dmPolicy="open" and allowFrom includes "*"', () => {
    const result = PulseboardAccountSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });

  it("passes when dmPolicy is not open (no allowFrom required)", () => {
    const result = PulseboardAccountSchema.safeParse({
      dmPolicy: "pairing",
    });
    expect(result.success).toBe(true);
  });
});

describe("PulseboardConfigSchema", () => {
  it("supports nested accounts", () => {
    const result = PulseboardConfigSchema.safeParse({
      apiToken: "pb_live_main",
      userId: "main_user",
      accounts: {
        secondary: {
          apiToken: "pb_live_secondary",
          userId: "secondary_user",
        },
      },
    });
    expect(result.success).toBe(true);
  });

  it('rejects dmPolicy="open" without allowFrom="*" at top level', () => {
    const result = PulseboardConfigSchema.safeParse({
      dmPolicy: "open",
    });
    expect(result.success).toBe(false);
  });
});

describe("PulseboardChannelConfigSchema", () => {
  it("is defined", () => {
    expect(PulseboardChannelConfigSchema).toBeDefined();
  });

  it("has uiHints attached", () => {
    // buildChannelConfigSchema attaches uiHints to the schema object
    expect(PulseboardChannelConfigSchema).toHaveProperty("uiHints");
  });

  it("parses valid config", () => {
    const result = PulseboardChannelConfigSchema.safeParse({
      apiToken: "pb_live_token",
      userId: "alice",
    });
    expect(result.success).toBe(true);
  });
});

